class CoapMessage:
    def __init__(self):
        self.version = 1
        self.type = 0
        self.token_length = 0
        self.code = 0
        self.message_id = 0
        self.token = b''
        self.options = []
        self.payload = b''
        
    @staticmethod
    def parse(data):
        if len(data) < 4:
            return None
            
        msg = CoapMessage()
        header = struct.unpack('!BBH', data[:4])
        
        msg.version = (header[0] >> 6) & 0x03
        msg.type = (header[0] >> 4) & 0x03
        msg.token_length = header[0] & 0x0F
        msg.code = header[1]
        msg.message_id = header[2]
        
        offset = 4
        if msg.token_length > 0:
            msg.token = data[offset:offset + msg.token_length]
            offset += msg.token_length
            
        while offset < len(data):
            if data[offset] == 0xFF:
                offset += 1
                msg.payload = data[offset:]
                break
                
            option_delta = (data[offset] >> 4) & 0x0F
            option_length = data[offset] & 0x0F
            offset += 1
            
            if option_delta == 13:
                option_delta = data[offset] + 13
                offset += 1
            elif option_delta == 14:
                option_delta = struct.unpack('!H', data[offset:offset+2])[0] + 269
                offset += 2
                
            if option_length == 13:
                option_length = data[offset] + 13
                offset += 1
            elif option_length == 14:
                option_length = struct.unpack('!H', data[offset:offset+2])[0] + 269
                offset += 2
                
            option_value = data[offset:offset + option_length]
            offset += option_length
            
            msg.options.append((option_delta, option_value))
            
        return msg
    
    def build(self):
        header = struct.pack('!BBH',
                            (self.version << 6) | (self.type << 4) | self.token_length,
                            self.code,
                            self.message_id)
        
        message = header + self.token
        
        last_option_num = 0
        for option_num, option_value in self.options:
            delta = option_num - last_option_num
            length = len(option_value)
            
            option_header = (delta << 4) | length
            message += bytes([option_header])
            message += option_value
            last_option_num = option_num
            
        if self.payload:
            message += b'\xFF' + self.payload
            
        return message
    
    def get_path(self):
        path_parts = []
        current_option = 0
        
        for delta, value in self.options:
            current_option += delta
            if current_option == 11:
                path_parts.append(value.decode('utf-8'))
                
        return '/' + '/'.join(path_parts) if path_parts else '/'

class CoapServer:
    GET = 1
    POST = 2
    PUT = 3
    DELETE = 4
    
    CREATED = 65
    DELETED = 66
    VALID = 67
    CHANGED = 68
    CONTENT = 69
    BAD_REQUEST = 128
    NOT_FOUND = 132
    METHOD_NOT_ALLOWED = 133
    
    TYPE_CON = 0
    TYPE_NON = 1
    TYPE_ACK = 2
    
    def __init__(self, host='0.0.0.0', port=5683):
        self.host = host
        self.port = port
        self.sock = None
        self.resources = {}
        self.running = False
        
    def register_resource(self, path, get_handler=None, put_handler=None, post_handler=None, delete_handler=None):
        self.resources[path] = {
            'get': get_handler,
            'put': put_handler,
            'post': post_handler,
            'delete': delete_handler
        }
        
    def start(self):
        self.sock = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
        self.sock.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
        self.sock.bind((self.host, self.port))
        self.sock.settimeout(0.1)
        self.running = True
        print(f"CoAP server started on {self.host}:{self.port}")
        
    def stop(self):
        self.running = False
        if self.sock:
            self.sock.close()
            
    def create_response(self, request, code, payload=b'', content_format=None):
        response = CoapMessage()
        response.version = 1
        response.type = self.TYPE_ACK if request.type == self.TYPE_CON else self.TYPE_NON
        response.code = code
        response.message_id = request.message_id
        response.token = request.token
        response.token_length = len(response.token)
        
        if content_format is not None:
            response.options.append((12, bytes([content_format])))
            
        if isinstance(payload, str):
            payload = payload.encode('utf-8')
        response.payload = payload
        
        return response
        
    def handle_request(self, data, addr):
        request = CoapMessage.parse(data)
        if not request:
            return
            
        path = request.get_path()
        method_code = request.code
        
        if path not in self.resources:
            response = self.create_response(request, self.NOT_FOUND, b'Not Found')
            self.sock.sendto(response.build(), addr)
            return
            
        resource = self.resources[path]
        handler = None
        
        if method_code == self.GET:
            handler = resource['get']
        elif method_code == self.PUT:
            handler = resource['put']
        elif method_code == self.POST:
            handler = resource['post']
        elif method_code == self.DELETE:
            handler = resource['delete']
            
        if handler is None:
            response = self.create_response(request, self.METHOD_NOT_ALLOWED, b'Method Not Allowed')
            self.sock.sendto(response.build(), addr)
            return
            
        try:
            result = handler(request.payload)
            
            if method_code == self.GET:
                response = self.create_response(request, self.CONTENT, result, content_format=0)
            elif method_code == self.PUT:
                response = self.create_response(request, self.CHANGED, result)
            elif method_code == self.POST:
                response = self.create_response(request, self.CREATED, result)
            elif method_code == self.DELETE:
                response = self.create_response(request, self.DELETED, result)
            else:
                response = self.create_response(request, self.BAD_REQUEST, b'Bad Request')
                
        except Exception as e:
            print(f"Error handling request: {e}")
            response = self.create_response(request, self.BAD_REQUEST, str(e).encode())
            
        self.sock.sendto(response.build(), addr)
        
    def run(self):
        while self.running:
            try:
                data, addr = self.sock.recvfrom(1024)
                self.handle_request(data, addr)
            except OSError:
                continue
            except KeyboardInterrupt:
                break
                
        self.stop()

# Simulated sensor and actuator state
temperature = 22.5
light_state = False

def get_temperature(payload):
    global temperature
    return f"{temperature:.1f}".encode()

def get_light(payload):
    global light_state
    state = "on" if light_state else "off"
    return state.encode()

def put_light(payload):
    global light_state
    command = payload.decode('utf-8').strip().lower()
    
    if command == "on":
        light_state = True
        print("Light turned ON")
        return b"Light turned on"
    elif command == "off":
        light_state = False
        print("Light turned OFF")
        return b"Light turned off"
    else:
        raise ValueError("Invalid command. Use 'on' or 'off'")

